from flask import Flask, request, session, redirect, url_for, render_template_string
from werkzeug.security import generate_password_hash, check_password_hash
from datetime import datetime, timedelta
import time
import hashlib
import secrets

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# In-memory storage for users and rate limiting
users = {}
rate_limits = {}

# Rate limiting configuration
MAX_LOGIN_ATTEMPTS = 5
RATE_LIMIT_WINDOW = 300  # 5 minutes

def is_rate_limited(ip_address):
    if ip_address not in rate_limits:
        rate_limits[ip_address] = []
    
    now = time.time()
    # Remove old attempts
    rate_limits[ip_address] = [attempt for attempt in rate_limits[ip_address] if now - attempt < RATE_LIMIT_WINDOW]
    
    if len(rate_limits[ip_address]) >= MAX_LOGIN_ATTEMPTS:
        return True
    
    rate_limits[ip_address].append(now)
    return False

def generate_secure_token():
    return secrets.token_urlsafe(32)

@app.route('/')
def index():
    if 'user_id' in session:
        return f'Hello {users[session["user_id"]]["username"]}! <a href="/logout">Logout</a>'
    return '<a href="/login">Login</a> | <a href="/register">Register</a>'

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        
        if username in users:
            return 'Username already exists'
        
        # Hash password with strong algorithm
        hashed = generate_password_hash(password, method='pbkdf2:sha256')
        users[username] = {
            'username': username,
            'password': hashed
        }
        return 'Registered successfully'
    
    return '''
    <form method="post">
        Username: <input type="text" name="username"><br>
        Password: <input type="password" name="password"><br>
        <input type="submit" value="Register">
    </form>
    '''

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        ip_address = request.remote_addr
        
        if is_rate_limited(ip_address):
            return 'Too many login attempts. Please try again later.'
        
        if username not in users:
            return 'Invalid credentials'
        
        stored_hash = users[username]['password']
        
        if check_password_hash(stored_hash, password):
            session['user_id'] = username
            session.permanent = True
            return redirect(url_for('index'))
        else:
            return 'Invalid credentials'
    
    return '''
    <form method="post">
        Username: <input type="text" name="username"><br>
        Password: <input type="password" name="password"><br>
        <input type="submit" value="Login">
    </form>
    '''

@app.route('/logout')
def logout():
    session.pop('user_id', None)
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=False)